import { db } from "../firebase"; // ajusta ruta si es necesario
import { collection, getDocs } from "firebase/firestore";
import { useEffect, useState } from "react";

const FirebaseTest = () => {
  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const obtenerProductos = async () => {
      try {
        const querySnapshot = await getDocs(collection(db, "products"));

        const lista = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));

        console.log("🔥 Datos reales en Firebase:", lista);
        setProductos(lista);

      } catch (error) {
        console.error("❌ Error al obtener productos:", error);
      } finally {
        setLoading(false);
      }
    };

    obtenerProductos();
  }, []);

  if (loading) {
    return <div>Cargando datos de Firebase...</div>;
  }

  return (
    <div style={{ padding: '20px', backgroundColor: '#f0f0f0', margin: '20px', borderRadius: '8px' }}>
      <h2>🔥 Verificación Directa de Firebase</h2>
      <p><strong>Total de productos en Firebase:</strong> {productos.length}</p>

      {productos.length === 0 ? (
        <p style={{ color: 'orange' }}>⚠️ No hay productos en Firebase todavía</p>
      ) : (
        <div>
          <h3>Productos Guardados:</h3>
          {productos.map((producto, index) => (
            <div key={producto.id} style={{ 
              border: '1px solid #ccc', 
              padding: '10px', 
              margin: '10px 0', 
              borderRadius: '4px',
              backgroundColor: 'white'
            }}>
              <h4>#{index + 1} - {producto.part_number || 'Sin número de parte'}</h4>
              <p><strong>ID:</strong> {producto.id}</p>
              <p><strong>Descripción:</strong> {producto.description || 'Sin descripción'}</p>
              <p><strong>Cliente:</strong> {producto.customer_name || 'Sin cliente'}</p>
              <p><strong>Inspecciones:</strong> {producto.quality_inspections?.length || 0} inspecciones</p>

              {producto.quality_inspections && producto.quality_inspections.length > 0 && (
                <div style={{ marginTop: '10px', padding: '10px', backgroundColor: '#f9f9f9' }}>
                  <h5>Inspecciones Configuradas:</h5>
                  {producto.quality_inspections.map((inspeccion, idx) => (
                    <div key={idx} style={{ marginLeft: '10px', fontSize: '14px' }}>
                      • {inspeccion.inspection_name} - 
                      Método: {inspeccion.inspection_method} - 
                      {inspeccion.inspection_method === 'aql' && ` AQL: ${inspeccion.aql_percentage}%`}
                      {inspeccion.inspection_method === 'muestreo' && ` Cantidad: ${inspeccion.sampling_quantity}`}
                      {inspeccion.inspection_method === '100%' && ` Inspección 100%`}
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default FirebaseTest;
